import { Article } from '../types';
import ArticleCard from './articles/ArticleCard';

interface ArticlesProps {
  articles: Article[];
  onSelectArticle: (article: Article) => void;
  showFilters: boolean;
}

const Articles: React.FC<ArticlesProps> = ({ articles, onSelectArticle, showFilters }) => {
  return (
    <div className="w-full stagger-fade-in-up-trigger">
      <div className="text-center mb-16 px-4">
        <h2 className="text-[24px] md:text-[28px] lg:text-[32px] font-black text-white mb-6 uppercase tracking-tight">
          LATEST <span className="text-[#e62e2e]">ARTICLES</span>
        </h2>
        <p className="text-gray-500 max-w-2xl mx-auto text-[10px] sm:text-[11px] leading-relaxed font-bold tracking-[0.3em] uppercase opacity-70">
          Latest Articles are weekly pieces created by me, published through my headless CMS powered by a Firebase backend.
        </p>
      </div>

      {articles.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 max-w-7xl mx-auto px-4 stagger-fade-in-up">
          {articles.map((article, index) => (
            <ArticleCard 
              key={article.id} 
              article={article} 
              onClick={() => onSelectArticle(article)} 
              style={{ transitionDelay: `${index * 150}ms` }}
            />
          ))}
        </div>
      ) : (
        <div className="text-center py-20">
            <h3 className="text-[10px] font-bold mb-1 uppercase tracking-[0.4em] text-gray-600">No Articles Available</h3>
            <p className="text-[8px] text-gray-700 uppercase tracking-widest">Awaiting CMS link...</p>
        </div>
      )}
    </div>
  );
};

export default Articles;

import React, { useState, useEffect } from 'react';
import { Article } from '../types';
import { getTrendingArticles } from '../api/cms';

interface GlobalTrendingProps {
  onSelectArticle: (article: Article) => void;
}

const TrendingCard: React.FC<{ article: Article; onClick: () => void; index: number }> = ({ article, onClick, index }) => {
  return (
    <div 
      onClick={onClick}
      style={{ transitionDelay: `${index * 150}ms` }}
      className="cursor-pointer group bg-[#161618] border border-white/5 rounded-2xl p-8 flex flex-col h-full transition-all duration-300 hover:border-white/10 hover:bg-[#1c1c1e]"
    >
      <h3 className="text-xl sm:text-2xl font-bold text-white mb-6 leading-tight line-clamp-2">
        {article.title}
      </h3>
      <p className="text-sm text-gray-400 mb-10 flex-grow leading-relaxed font-light opacity-90 line-clamp-6">
        {article.excerpt}
      </p>
      <div className="mt-auto">
        <span className="text-[#00bcd4] text-sm font-semibold flex items-center gap-2 group-hover:gap-3 transition-all">
          Read Full Analysis <span className="text-lg">→</span>
        </span>
      </div>
    </div>
  );
};

const GlobalTrending: React.FC<GlobalTrendingProps> = ({ onSelectArticle }) => {
  const [trendingArticles, setTrendingArticles] = useState<Article[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    getTrendingArticles().then(articles => {
      setTrendingArticles(articles);
      setIsLoading(false);
    });
  }, []);

  return (
    <div className="w-full max-w-7xl mx-auto px-4 stagger-fade-in-up-trigger">
      <div className="text-center mb-16">
        <h2 className="text-[24px] md:text-[28px] lg:text-[32px] font-black text-white mb-6 uppercase tracking-tight">
          GLOBAL <span className="text-[#e62e2e]">TRENDING</span>
        </h2>
        <p className="text-gray-500 max-w-3xl mx-auto text-[10px] sm:text-[11px] leading-relaxed font-bold tracking-[0.3em] uppercase opacity-70">
          AI-powered summaries of the most pressing geopolitical and economic topics, refreshed twice daily.
        </p>
      </div>

      {isLoading ? (
        <div className="flex justify-center items-center py-20">
          <div className="w-6 h-6 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 stagger-fade-in-up">
          {trendingArticles.map((article, idx) => (
            <TrendingCard
              key={article.id}
              article={article}
              index={idx}
              onClick={() => onSelectArticle(article)}
            />
          ))}
        </div>
      )}
    </div>
  );
};

export default GlobalTrending;
